class Solution {
public:
    ListNode* removeZeroSumSublists(ListNode* head) {
        ListNode dummy(0);
        dummy.next = head;
        int prefix = 0;
        unordered_map<int, ListNode*> seen;
        seen[0] = &dummy;
        while (head) {
            prefix += head->val;
            if (seen.find(prefix) != seen.end()) {
                ListNode* node = seen[prefix]->next;
                int tmp = prefix + node->val;
                seen.erase(prefix);
                while (node != head) {
                    seen.erase(tmp);
                    node = node->next;
                    tmp += node->val;
                }
                seen[prefix]->next = head->next;
            } else {
                seen[prefix] = head;
            }
            head = head->next;
        }
        return dummy.next;
    }
};
efficiency: HIGH
time complexity: O(N)
space complexity: O(N)
energy implications: LOW
explanation: Uses a dummy node and an unordered map to track prefix sums and corresponding nodes, efficiently removing zero-sum sublists in a single pass.
